const dadosIa = $input.item.json;

let cidade = dadosIa.cidade || '';
let uf = dadosIa.uf || '';
let limite = dadosIa.limite || 20;

// Se a IA mandou tudo num campo "query" (ex: "Diadema, SP" ou "Diadema - SP")
if (dadosIa.query && !cidade) {
    let partes = dadosIa.query.split(/,| - |-/); // Separa usando vírgula ou traço
    cidade = partes[0] ? partes[0].trim() : '';
    uf = partes[1] ? partes[1].trim() : '';
}

// Retorna limpo e com fallbacks de segurança
return {
    json: {
        cidade: cidade || 'Birigui',
        uf: uf || 'SP',
        limite: limite
    }
};

// Função para corrigir caracteres corrompidos (UTF-8 vs ISO-8859-1)
function fixEncoding(text) {
    if (typeof text !== 'string') return text;
    try {
        return decodeURIComponent(escape(text));
    } catch (e) {
        return text
            .replace(/茫/g, 'ã')
            .replace(/茅/g, 'é')
            .replace(/铆/g, 'í')
            .replace(/贸/g, 'ó')
            .replace(/煤/g, 'ú')
            .replace(/锚/g, 'ê')
            .replace(/芒/g, 'â')
            .replace(/SA煤de/g, 'Saúde');
    }
}

const payload = $input.item.json || {};
const codigo = payload.codigo;
const clientesBrutos = Array.isArray(payload.retorno) ? payload.retorno : [];

// Se a API devolveu erro (cidade não encontrada, dataset inexistente, etc.)
// devolva um envelope vazio porém válido, sinalizando para o agente cair na
// próxima fonte (Oporttuna ou RAG/planilha).
if (codigo && codigo >= 400) {
    return {
        json: {
            ok: false,
            fonte: 'carteira_sameka',
            total: 0,
            clientes: [],
            error: payload.mensagem || 'Consulta na carteira Sameka falhou',
            codigo: codigo
        }
    };
}

const clientesFiltrados = clientesBrutos.map(c => ({
    // Identificação
    cnpj: c.cnpjCompleto,
    tipoCNPJ: c.tipoCNPJ,
    empresa: fixEncoding(c.razaoSocial),
    nomeFantasia: fixEncoding(c.nomeFantasia),
    situacaoCadastral: fixEncoding(c.situacaoCadastral),

    // Localização para o Roteiro
    endereco: fixEncoding(c.enderecoCompleto),
    bairro: fixEncoding(c.bairro),
    cidade: fixEncoding(c.cidade),
    uf: c.uf,
    cep: c.cep,
    tipoLogradouro: c.tipoLogradouro,

    // Contatos diretos
    telefones: c.telefones || [],
    emails: c.emails || [],

    // Mídia
    fotos: c.fotos || [],

    // Presença Digital e Redes Sociais
    redesSociais: c.redesSociais || [],
    possuiPresencaDigital: c.possuiPresencaDigital,

    // Inteligência de Vendas
    natureza: fixEncoding(c.naturezaJuridica),
    faturamento: c.indicadorAtividade?.faixaFaturamento,
    score: {
        nota: c.notaICP,
        classificacao: c.classificacaoICP,
        descricao: fixEncoding(c.descricaoClassificacaoICP)
    },

    // Marcador de origem — clientes da carteira Sameka
    empresaCliente: c.empresaCliente || 'SIM',
    empresaProspect: c.empresaProspect || 'NAO',
    fonte: 'carteira_sameka'
}));

return {
    json: {
        ok: true,
        fonte: 'carteira_sameka',
        total: clientesFiltrados.length,
        clientes: clientesFiltrados
    }
};
